int factorial(int n) {
    if (n <= 1) return 1;  // base case
    return n * factorial(n - 1);  // recursive case
}

int fibonacci(int n) {
    if (n <= 1) return n;
    return fibonacci(n - 1) + fibonacci(n - 2);
}

int main() {
    printf("%d\n", factorial(5));    // 120
    printf("%d\n", fibonacci(10));   // 55
}

