int memo[100];

int fib(int n) {
    if (n <= 1) return n;
    if (memo[n] != -1) return memo[n];
    memo[n] = fib(n - 1) + fib(n - 2);
    return memo[n];
}

int main() {
    memset(memo, -1, sizeof(memo));
    printf("%d\n", fib(40));  // 102334155 (fast!)
}

