void permute(int *nums, int n, int *used, int *path, int depth) {
    if (depth == n) {
        for (int i = 0; i < n; i++) printf("%d ", path[i]);
        printf("\n");
        return;
    }
    for (int i = 0; i < n; i++) {
        if (used[i]) continue;
        used[i] = 1;
        path[depth] = nums[i];
        permute(nums, n, used, path, depth + 1);
        used[i] = 0;
    }
}

int main() {
    int nums[] = {1, 2, 3};
    int used[3] = {0}, path[3];
    permute(nums, 3, used, path, 0);
    return 0;
}

